Here's how to save/restore draft text using MAUI's lifecycle events and `Preferences`:

**In your NotePage.xaml.cs:**

```csharp
public partial class NotePage : ContentPage
{
    private const string DraftKey = "note_draft_text";

    public NotePage()
    {
        InitializeComponent();

        // Restore draft on page load
        DraftEditor.Text = Preferences.Get(DraftKey, string.Empty);
    }

    protected override void OnAppearing()
    {
        base.OnAppearing();

        // Subscribe to lifecycle events
        App.Current.Windows[0].Deactivated += OnAppBackgrounded;
        App.Current.Windows[0].Resumed += OnAppResumed;
    }

    protected override void OnDisappearing()
    {
        base.OnDisappearing();

        App.Current.Windows[0].Deactivated -= OnAppBackgrounded;
        App.Current.Windows[0].Resumed -= OnAppResumed;
    }

    private void OnAppBackgrounded(object sender, EventArgs e)
    {
        // Save draft when app goes to background
        Preferences.Set(DraftKey, DraftEditor.Text ?? string.Empty);
    }

    private void OnAppResumed(object sender, EventArgs e)
    {
        // Restore draft when app comes back (handles process termination case)
        DraftEditor.Text = Preferences.Get(DraftKey, string.Empty);
    }

    private void OnSaveClicked(object sender, EventArgs e)
    {
        // Clear draft after intentional save
        Preferences.Remove(DraftKey);
    }
}
```

**Key points:**

- **`Deactivated`** fires when the app goes to background — persist the draft here.
- **`Resumed`** fires when the app returns — useful if the OS killed the process.
- **`Preferences`** is lightweight key-value storage ideal for small text. For large notes, use `FileSystem.AppDataDirectory` with file I/O instead.
- Remove the draft on intentional save so stale data doesn't reappear.
